UPDATE STOCVOCM SET
      PROGRESS_CD = #{PROGRESS_CD}
    , RECV_DATE   = (#{RECV_DATE}, 'YYYY-MM-DD HH24:MI:SS')
    , DS_USER_ID  = #{DS_USER_ID}
    , CD_DATE     = #{CD_DATE}
    , DS_DATE     = (#{DS_DATE}, 'YYYY-MM-DD HH24:MI:SS')
    , DF_RMK      = #{DF_RMK}
    , DS_ATTACH_FILE_NO = #{DS_ATTACH_FILE_NO}
    , MOD_DATE    = SYSDATE
    , MOD_USER_ID = #{ses.userId}
WHERE GATE_CD    = #{ses.gateCd}
  AND COMPANY_CD = #{COMPANY_CD}
  AND VC_NO      = #{VC_NO}
